/* ================================
   n8n Chat – Overrides mínimos
   TriadeFlow × Pestiscos Alimentos
   ================================ */

/* 1) Ajustes leves nos tokens existentes (sem criar DOM novo) */
:root {
  /* canto mais premium sem quebrar layout */
  --chat--border-radius: 0.75rem;

  /* header com mais respiro para comportar a logo grande */
  --chat--header--padding: calc(var(--chat--spacing) * 1.25);

  /* overlay sutil escuro + LOGO grande (sem alterar HTML) */
  /* Importante: o primeiro background (gradiente) fica por cima do segundo (imagem) */
  --chat--header--background:
    linear-gradient(180deg, rgba(16, 19, 48, 0.75) 0%, rgba(16, 19, 48, 0.55) 100%),
    url("https://ffdokuygidunwtrtjjxe.supabase.co/storage/v1/object/public/triadeflow/WhatsApp%20Image%202025-09-06%20at%2022.47.38.jpeg");
}

/* 2) Header padrão do n8n com a logo como background grandão */
.chat-header {
  /* garante área para destacar a marca */
  min-height: 200px;

  /* usa a variável já existente que agora é composta (gradiente + logo) */
  background: var(--chat--header--background);

  /* posicionamento da logo e overlay */
  background-repeat: no-repeat, no-repeat;
  background-position: center center, center center;

  /* ajuste de tamanho da logo (aumente para 80%/90% se quiser ainda maior) */
  background-size: cover, 70%;

  /* mantém cores definidas pelos tokens originais */
  color: var(--chat--header--color);
  border-top: var(--chat--header--border-top);
  border-bottom: var(--chat--header--border-bottom);
  border-left: var(--chat--header--border-left);
  border-right: var(--chat--header--border-right);
}

/* melhora a legibilidade se houver título/subtítulo no header */
.chat-header * {
  text-shadow: 0 1px 2px rgba(0,0,0,.35);
}

/* 3) Bolhas — acabamento sutil mantendo estrutura original */
.chat-message {
  max-width: 50%; /* respeita o seu padrão; ajuste se quiser */
  border-radius: var(--chat--message--border-radius);
  transition: transform var(--chat--transition-duration) ease,
              box-shadow var(--chat--transition-duration) ease;
}

.chat-message.bot {
  background: var(--chat--message--bot--background);
  color: var(--chat--message--bot--color);
  border: var(--chat--message--bot--border);
  box-shadow: 0 8px 18px rgba(16,19,48,0.08);
}

.chat-message.user {
  background: var(--chat--message--user--background);
  color: var(--chat--message--user--color);
  border: var(--chat--message--user--border);
  box-shadow: 0 8px 18px rgba(16,19,48,0.12);
  margin-left: auto; /* mantém alinhamento à direita */
}

/* micro-hover sutil (não interfere no mobile) */
@media (hover: hover) {
  .chat-message:hover { transform: translateY(-1px); }
}

/* 4) Código/pre — polimento mínimo usando token existente */
.chat-message pre,
.chat-message code,
.chat-message pre code {
  background: var(--chat--message--pre--background);
  border-radius: 0.5rem;
}

/* 5) Footer — opcional: vidro leve, sem mudar estrutura */
.chat-footer {
  background: var(--chat--footer--background);
  color: var(--chat--footer--color);
  backdrop-filter: blur(8px);
}

